const body = $input.first().json.body || $input.first().json;
const projectId = body.projectId || 'unknown';
const requirements = body.requirements || [];
const techConstraints = body.techConstraints || {};
const runId = body.runId || `arch-eval-${Date.now()}`;

if (!requirements || (Array.isArray(requirements) && requirements.length === 0 && typeof requirements !== 'string')) {
  throw new Error('requirements is required in the request body');
}

const reqList = typeof requirements === 'string'
  ? requirements.split(/[,;\n]/).map(r => r.trim()).filter(Boolean)
  : Array.isArray(requirements) ? requirements : [requirements];

const hasRealtime = reqList.some(r => /real.?time|websocket|live|stream/i.test(r));
const hasHighScale = reqList.some(r => /scale|concurrent|throughput|high.?load/i.test(r));
const hasOffline = reqList.some(r => /offline|pwa|local.?first/i.test(r));
const hasML = reqList.some(r => /machine.?learning|ai|ml|model|inference/i.test(r));
const isSimple = reqList.length <= 3 && !hasRealtime && !hasHighScale;

const preferredLang = techConstraints.language || 'TypeScript';
const preferredDb = techConstraints.database || 'PostgreSQL';
const deployTarget = techConstraints.deployment || 'self-hosted';

const options = [
  {
    id: 'arch-a',
    name: 'Monolith (Express/Next.js)',
    style: 'monolith',
    description: `Single deployable unit with ${preferredLang}. Express 5 API + Next.js frontend. ${preferredDb} database with Drizzle ORM. Simple deployment, fast iteration.`,
    stack: {
      backend: `Express 5 (${preferredLang})`,
      frontend: 'Next.js 15 + React 19',
      database: `${preferredDb} + Drizzle ORM`,
      deployment: deployTarget === 'cloud' ? 'Vercel + managed DB' : 'Docker Compose on single host',
      messaging: hasRealtime ? 'WebSocket (ws)' : 'REST only'
    },
    suitability: {
      realtime: hasRealtime ? 'partial — ws addon required' : 'n/a',
      scale: hasHighScale ? 'limited — vertical only' : 'sufficient',
      offline: hasOffline ? 'not supported natively' : 'n/a',
      ml: hasML ? 'API call to external service' : 'n/a'
    }
  },
  {
    id: 'arch-b',
    name: 'Modular Monolith (Domain Modules)',
    style: 'modular-monolith',
    description: `Domain-driven modules within a single deployable. Clear boundaries between modules but shared deployment. ${preferredDb} with schema-per-module. Event bus for inter-module communication.`,
    stack: {
      backend: `Fastify (${preferredLang}) with module loader`,
      frontend: 'React 19 SPA + Vite',
      database: `${preferredDb} with schema isolation per module`,
      deployment: 'Docker with module health checks',
      messaging: 'Internal event bus (EventEmitter / BullMQ)'
    },
    suitability: {
      realtime: hasRealtime ? 'good — SSE/WebSocket per module' : 'n/a',
      scale: hasHighScale ? 'good — can extract hot modules later' : 'sufficient',
      offline: hasOffline ? 'partial — API-first enables offline cache' : 'n/a',
      ml: hasML ? 'dedicated ML module with queue' : 'n/a'
    }
  },
  {
    id: 'arch-c',
    name: 'Service-Oriented (Micro-ish)',
    style: 'microservices',
    description: `Separate services per bounded context. Independent deployments with API gateway. Best for teams > 3 or high-scale requirements. Higher operational complexity.`,
    stack: {
      backend: `Multiple ${preferredLang} services + API gateway (Kong/Traefik)`,
      frontend: 'React 19 micro-frontends or monolithic SPA',
      database: `${preferredDb} per service (database-per-service pattern)`,
      deployment: 'Docker Compose / Kubernetes',
      messaging: 'NATS or RabbitMQ for async, gRPC for sync'
    },
    suitability: {
      realtime: hasRealtime ? 'excellent — dedicated realtime service' : 'overkill',
      scale: hasHighScale ? 'excellent — independent scaling' : 'overkill for current needs',
      offline: hasOffline ? 'good — BFF pattern for offline sync' : 'n/a',
      ml: hasML ? 'excellent — isolated ML service with GPU' : 'overkill'
    }
  }
];

return [{
  json: {
    projectId,
    runId,
    requirementCount: reqList.length,
    requirements: reqList,
    techConstraints: { language: preferredLang, database: preferredDb, deployment: deployTarget },
    signals: { hasRealtime, hasHighScale, hasOffline, hasML, isSimple },
    options
  }
}];

const input = $input.first().json;
const options = input.options;
const signals = input.signals;

const CRITERIA = [
  { name: 'time_to_market', weight: 0.25, description: 'How quickly can we ship an MVP?' },
  { name: 'scalability', weight: 0.20, description: 'Can it grow with demand?' },
  { name: 'maintainability', weight: 0.20, description: 'How easy is it to evolve and debug?' },
  { name: 'operational_complexity', weight: 0.15, description: 'How much DevOps overhead?' },
  { name: 'cost_efficiency', weight: 0.10, description: 'Infrastructure and development cost' },
  { name: 'team_fit', weight: 0.10, description: 'Does it match team skills and size?' }
];

const RAW_SCORES = {
  'arch-a': {
    time_to_market: 9,
    scalability: signals.hasHighScale ? 4 : 7,
    maintainability: 8,
    operational_complexity: 9,
    cost_efficiency: 9,
    team_fit: 9
  },
  'arch-b': {
    time_to_market: 7,
    scalability: signals.hasHighScale ? 7 : 8,
    maintainability: 9,
    operational_complexity: 7,
    cost_efficiency: 7,
    team_fit: 7
  },
  'arch-c': {
    time_to_market: 4,
    scalability: 9,
    maintainability: 6,
    operational_complexity: 3,
    cost_efficiency: 4,
    team_fit: 4
  }
};

if (signals.hasRealtime) {
  RAW_SCORES['arch-b'].scalability += 1;
  RAW_SCORES['arch-c'].scalability += 1;
}
if (signals.isSimple) {
  RAW_SCORES['arch-a'].time_to_market = 10;
  RAW_SCORES['arch-a'].maintainability = 9;
}

const scoredOptions = options.map(opt => {
  const scores = RAW_SCORES[opt.id] || RAW_SCORES['arch-a'];
  let weightedTotal = 0;

  const breakdown = CRITERIA.map(c => {
    const raw = Math.min(10, Math.max(1, scores[c.name] || 5));
    const weighted = raw * c.weight;
    weightedTotal += weighted;
    return {
      criterion: c.name,
      weight: c.weight,
      rawScore: raw,
      weightedScore: Math.round(weighted * 100) / 100
    };
  });

  return {
    id: opt.id,
    name: opt.name,
    style: opt.style,
    totalScore: Math.round(weightedTotal * 100) / 100,
    maxPossible: 10,
    breakdown
  };
});

scoredOptions.sort((a, b) => b.totalScore - a.totalScore);

const winner = scoredOptions[0];
const runnerUp = scoredOptions[1];
const gap = Math.round((winner.totalScore - runnerUp.totalScore) * 100) / 100;

const recommendation = {
  preferred: winner.id,
  preferredName: winner.name,
  score: winner.totalScore,
  confidence: gap > 1.5 ? 'high' : gap > 0.5 ? 'medium' : 'low',
  rationale: gap > 1.5
    ? `${winner.name} clearly outperforms alternatives (${gap} point lead).`
    : gap > 0.5
    ? `${winner.name} leads by ${gap} points. Consider ${runnerUp.name} if ${runnerUp.breakdown.sort((a,b) => b.rawScore - a.rawScore)[0].criterion} is more important than expected.`
    : `${winner.name} and ${runnerUp.name} are close (${gap} point gap). Decision should factor in team preference.`,
  tradeoffs: [
    `${winner.name}: strongest in ${winner.breakdown.sort((a,b) => b.rawScore - a.rawScore)[0].criterion}`,
    `${runnerUp.name}: strongest in ${runnerUp.breakdown.sort((a,b) => b.rawScore - a.rawScore)[0].criterion}`,
    `Weakest area for recommended: ${winner.breakdown.sort((a,b) => a.rawScore - b.rawScore)[0].criterion} (${winner.breakdown.sort((a,b) => a.rawScore - b.rawScore)[0].rawScore}/10)`
  ]
};

return [{
  json: {
    ...input,
    criteria: CRITERIA,
    scoredOptions,
    recommendation
  }
}];

// Auto-converted from Set v3 (n8n 2.15.x SetV2 node crashes at SetV2.node.ts:352)
return [{ json: {
  "projectId": $json.projectId,
  "runId": $json.runId,
  "recommendedArchitecture": $json.recommendation.preferredName,
  "confidence": $json.recommendation.confidence,
  "rationale": $json.recommendation.rationale,
  "comparisonMatrix": JSON.stringify({ criteria: $json.criteria.map(c => c.name), options: $json.scoredOptions.map(o => ({ id: o.id, name: o.name, total: o.totalScore, scores: Object.fromEntries(o.breakdown.map(b => [b.criterion, b.rawScore])) })), recommendation: $json.recommendation }),
  "fullOptions": JSON.stringify($json.options)
} }];

