  "success": true,
  "result": JSON.stringify({ projectId: $('Compile Matrix').first().json.projectId, runId: $('Compile Matrix').first().json.runId, recommended: $('Compile Matrix').first().json.recommendedArchitecture, confidence: $('Compile Matrix').first().json.confidence, rationale: $('Compile Matrix').first().json.rationale })
